            aOrbiterK = RotL64((aOrbiterK * 2463155120890677321U), 37U);
            //
            aOrbiterB = (aOrbiterB + aOrbiterD) + 12792270571180756462U;
            aOrbiterF = ((aOrbiterF ^ aOrbiterB) ^ 16692669934903732503U) ^ aNonceWordD;
